//! Binding definitions for the `LaTeXML` converter, reimplemented in Rust
#![recursion_limit = "1024"]

#[macro_use]
extern crate latexml_codegen;
// re-export small auxiliary macros
#[macro_use]
pub mod macros;
// Prelude for writing bindings
#[macro_use]
pub mod prelude;
// The TeX/LaTeX/eTeX/PdfTeX kernels
#[macro_use]
pub mod engine;
// Supported LaTeX packages
#[macro_use]
pub mod package;

// TODO: This entire file may be better left generated by latexml_codegen at compile time?
// that way it will always be dynamically updated based on the files in
//  latexml_package/src/package
use latexml_core::common::error::Result;
